import React, { Component } from 'react'

class counter extends Component {
    constructor(props){
        super(props);
        this.state={
            count:0
        }
        }
    render() {
    return (
      <div>
        <div>
        count:{this.state.count}
        <button onClick={()=>this.setState({count:this.state.count+1})}>+</button>
        </div>
      </div>
    )
  }
}

export default counter
